def group_by_activity(users):
    result = {"power": [], "regular": [], "casual": []}
    for user in users:
        uid = user["user_id"]
        count = user["events"]
        if count >= 30:
            result["power"].append(uid)
        elif count >= 10:
            result["regular"].append(uid)
        else:
            result["casual"].append(uid)
    return result

result = group_by_activity(users)
for level in ["power", "regular", "casual"]:
    print(f"{level}: {result[level]}")

