]

def most_popular_per_category(orders):
    # Step 1: accumulate total qty per category+item
    totals = {}
    for order in orders:
        cat = order["category"]
        item = order["item"]
        key = (cat, item)
        if key not in totals:
            totals[key] = 0
        totals[key] += order["qty"]

    # Step 2: find max per category (two-dict tracker)
    top_item = {}
    top_qty = {}
    for (cat, item), qty in totals.items():
        if cat not in top_qty or qty > top_qty[cat]:
            top_item[cat] = item
            top_qty[cat] = qty

    result = {}
    for cat in top_item:
        result[cat] = (top_item[cat], top_qty[cat])
    return result

result = most_popular_per_category(orders)
for cat, (item, total) in sorted(result.items()):
    print(f"{cat}: {item} (total: {total})")

from datetime import datetime

events = [
    {"user_id": 1, "ts": "2024-03-01 08:00", "action": "view", "source": "google"},
    {"user_id": 1, "ts": "2024-03-01 08:05", "action": "click", "source": "google"},
    {"user_id": 1, "ts": "2024-03-01 10:00", "action": "view", "source": "email"},
    {"user_id": 1, "ts": "2024-03-01 10:02", "action": "purchase", "source": "email"},
    {"user_id": 2, "ts": "2024-03-01 09:00", "action": "view", "source": "direct"},
    {"user_id": 2, "ts": "2024-03-01 09:10", "action": "click", "source": "direct"},
    {"user_id": 2, "ts": "2024-03-01 12:00", "action": "view", "source": "google"}
]

def count_sessions_by_source(events, gap_minutes=30):
    # Step 1: group events by user
    by_user = {}
    for e in events:
        uid = e["user_id"]
        if uid not in by_user:
            by_user[uid] = []
        by_user[uid].append(e)

    # Step 2: sort each user's events by timestamp
    for uid in by_user:
        by_user[uid].sort(key=lambda x: x["ts"])

    # Step 3: walk through each user's events, detect session boundaries
    source_counts = {}
    for uid, user_events in by_user.items():
        session_source = user_events[0]["source"]
        prev_time = datetime.strptime(user_events[0]["ts"], "%Y-%m-%d %H:%M")

        for i in range(1, len(user_events)):
            curr_time = datetime.strptime(user_events[i]["ts"], "%Y-%m-%d %H:%M")
            diff_minutes = (curr_time - prev_time).total_seconds() / 60

            if diff_minutes > gap_minutes:
                # Close previous session
                if session_source not in source_counts:
                    source_counts[session_source] = 0
                source_counts[session_source] += 1
                # Start new session
                session_source = user_events[i]["source"]

            prev_time = curr_time

        # Close final session
        if session_source not in source_counts:
            source_counts[session_source] = 0
        source_counts[session_source] += 1

    return source_counts

result = count_sessions_by_source(events)
for source, count in sorted(result.items(), key=lambda x: -x[1]):
    print(f"{source}: {count}")
